/* WARNING: Script requires that SQLITE_DBCONFIG_DEFENSIVE be disabled */
PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE session_histories (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                session_id TEXT NOT NULL UNIQUE,
                started_at TEXT NOT NULL,
                ended_at TEXT NOT NULL,
                transcript TEXT NOT NULL,
                reply TEXT NOT NULL,
                peak_level REAL NOT NULL,
                mean_level REAL NOT NULL,
                auto_closed INTEGER NOT NULL,
                reopened_by_click INTEGER NOT NULL,
                mode TEXT NOT NULL,
                created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
            , user_id TEXT NOT NULL DEFAULT 'soj');
CREATE TABLE remember_entries (
                id TEXT PRIMARY KEY,
                memory TEXT NOT NULL,
                original_text TEXT NOT NULL DEFAULT '',
                created_at TEXT NOT NULL,
                updated_at TEXT NOT NULL
            , source_memory_id TEXT NOT NULL DEFAULT '', user_id TEXT NOT NULL DEFAULT '');
PRAGMA writable_schema=ON;
            USING fts5(
                memory,
                original_text,
                item_id UNINDEXED,
                tokenize=''unicode61''
            )');
CREATE TABLE IF NOT EXISTS 'remember_entries_fts_data'(id INTEGER PRIMARY KEY, block BLOB);
CREATE TABLE IF NOT EXISTS 'remember_entries_fts_idx'(segid, term, pgno, PRIMARY KEY(segid, term)) WITHOUT ROWID;
CREATE TABLE IF NOT EXISTS 'remember_entries_fts_content'(id INTEGER PRIMARY KEY, c0, c1, c2);
CREATE TABLE IF NOT EXISTS 'remember_entries_fts_docsize'(id INTEGER PRIMARY KEY, sz BLOB);
CREATE TABLE IF NOT EXISTS 'remember_entries_fts_config'(k PRIMARY KEY, v) WITHOUT ROWID;
            USING fts5(
                memory,
                original_text,
                item_id UNINDEXED,
                tokenize=''simple''
            )');
CREATE TABLE IF NOT EXISTS 'remember_entries_simple_fts_data'(id INTEGER PRIMARY KEY, block BLOB);
CREATE TABLE IF NOT EXISTS 'remember_entries_simple_fts_idx'(segid, term, pgno, PRIMARY KEY(segid, term)) WITHOUT ROWID;
CREATE TABLE IF NOT EXISTS 'remember_entries_simple_fts_content'(id INTEGER PRIMARY KEY, c0, c1, c2);
CREATE TABLE IF NOT EXISTS 'remember_entries_simple_fts_docsize'(id INTEGER PRIMARY KEY, sz BLOB);
CREATE TABLE IF NOT EXISTS 'remember_entries_simple_fts_config'(k PRIMARY KEY, v) WITHOUT ROWID;
CREATE TABLE remember_entry_embeddings (
                item_id TEXT PRIMARY KEY,
                source_text TEXT NOT NULL,
                embedding_model TEXT NOT NULL,
                embedding_json TEXT NOT NULL,
                updated_at TEXT NOT NULL
            , user_id TEXT NOT NULL DEFAULT '');
CREATE TABLE IF NOT EXISTS "api_tokens" ("token" VARCHAR(255) NOT NULL PRIMARY KEY, "user_id" VARCHAR(255) NOT NULL, "description" TEXT, "created_at" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE INDEX idx_session_histories_started_at
            ON session_histories(started_at DESC)
            ;
CREATE INDEX idx_remember_entries_updated_at
            ON remember_entries(updated_at DESC)
            ;
CREATE UNIQUE INDEX idx_remember_entries_source_memory_id
            ON remember_entries(source_memory_id)
            WHERE source_memory_id != ''
            ;
CREATE INDEX "apitoken_user_id" ON "api_tokens" ("user_id");
CREATE INDEX "rememberentry_user_id" ON "remember_entries" ("user_id");
CREATE UNIQUE INDEX "sessionhistory_session_id" ON "session_histories" ("session_id");
CREATE INDEX "sessionhistory_user_id" ON "session_histories" ("user_id");
CREATE INDEX idx_session_histories_user_id ON session_histories(user_id);
PRAGMA writable_schema=OFF;
COMMIT;
