INSERT INTO session_histories VALUES(267,'7493b659c3474a72afb64be6bc5820b1','2026-04-18T10:14:44+08:00','2026-04-18T10:14:49+08:00','我的儿子最近有啥好玩的事','大王，你儿子壮壮最近有件好玩的事：他在4月11日去打篮球啦！不过其他时候不是在和头发较劲，就是被薯片划了脸，倒是这打球的回忆最生动呢～',0.0,0.0,0,0,'cli','2026-04-18T10:14:44+08:00','soj');
INSERT INTO session_histories VALUES(268,'94065cf61f0f4eaa84101dc1f03bfd9a','2026-04-18T10:15:54+08:00','2026-04-18T10:16:00+08:00','我的儿子最近有啥好玩的事',unistr('大王，你家小家伙最近可真热闹呢！  \u000a- **运动小能手**：4月11日去打篮球，活力满满~  \u000a- **小倔强**：头发长到想剪，但死活不肯配合，估计在酝酿新发型宣言吧！  \u000a- **春游小插曲**：被同学“投喂”薯片时意外中奖——脸上多了道“勋章”，估计以后会变成家族冷笑话素材。  \u000a- **雨天小哲思**：公园地面有水，他居然说“水是地面的头发，乱踩不礼貌”，强行升华了不想玩的理由😂  \u000a\u000a要不要给他立个“今日份趣事日记”小本本？'),0.0,0.0,0,0,'cli','2026-04-18T10:15:54+08:00','soj');
