INSERT INTO session_histories VALUES(275,'a40fddbe528b475c94a2fe7f348d26f0','2026-04-18T10:37:32+08:00','2026-04-18T10:37:38+08:00','我最近是不是拔了颗牙','是的，大王，你昨天（2026-04-15）拔了颗智齿！医生用工具快速取出了牙齿，全程不到两分钟，你居然没觉得疼。今天（2026-04-16）你提到牙已经不疼了，看来恢复得不错~',0.0,0.0,0,0,'cli','2026-04-18T10:37:32+08:00','soj');
