INSERT INTO session_histories VALUES(278,'95051ad27ec746a89df75aa5826acd86','2026-04-18T11:03:13+08:00','2026-04-18T11:03:17+08:00','我最近是不是拔了个牙？','是的，大王，你4月15日拔了智齿，当时用工具轻松取出，全程无痛。4月16日记录显示拔牙后牙齿已不疼了。',0.0,0.0,0,0,'cli','2026-04-18T11:03:13+08:00','soj');
