INSERT INTO session_histories VALUES(362,'c17620d5cc0f4086a5ee1884c5f3b347','2026-04-18T18:43:38+08:00','2026-04-18T18:43:42+08:00','杜甫是谁','杜甫，唐代伟大诗人，生于公元712年，卒于公元770年。他的诗歌以深刻的社会关怀和精湛的艺术技巧著称，代表作有《春望》、《茅屋为秋风所破歌》等。杜甫被誉为“诗圣”，对中国文学产生了深远影响。',0.0,0.0,0,0,'cli','2026-04-18T18:43:38+08:00','soj');
