INSERT INTO session_histories VALUES(365,'a02b149cb46f4488a44d85295629a6b1','2026-04-18T18:48:10+08:00','2026-04-18T18:48:15+08:00','杜甫是谁','杜甫，中国唐代伟大诗人，生于公元712年，卒于公元770年。他的诗歌以深刻的社会关怀和精湛的艺术技巧著称，代表作有《春望》、《茅屋为秋风所破歌》等。杜甫被誉为“诗圣”，是中国文学史上最重要的诗人之一。',0.0,0.0,0,0,'cli','2026-04-18T18:48:10+08:00','soj');
