INSERT INTO session_histories VALUES(367,'4528c9aa21b24b08ac862b95bdeb05c3','2026-04-18T18:49:30+08:00','2026-04-18T18:49:34+08:00','杜甫','杜甫是唐代伟大的现实主义诗人，生于公元712年，卒于公元770年。他的诗歌以深刻的社会关怀和强烈的忧国忧民情怀著称，代表作品有《春望》、《茅屋为秋风所破歌》等。杜甫的诗歌对后世影响深远，被誉为“诗圣”。',0.0,0.0,0,0,'cli','2026-04-18T18:49:30+08:00','soj');
INSERT INTO session_histories VALUES(368,'74d69a5be7be427bb6e3fb18ed020047','2026-04-18T18:50:38+08:00','2026-04-18T18:50:43+08:00','红烧肉','红烧肉是一道传统的中国菜，通常由猪肉、糖、酱油、葱、姜等材料制成。它的特点是色泽红润，味道甜咸，口感软烂。红烧肉常作为家常菜或宴席菜肴，受到很多人的喜爱。你喜欢红烧肉吗？',0.0,0.0,0,0,'cli','2026-04-18T18:50:38+08:00','soj');
