INSERT INTO session_histories VALUES(461,'4fe4c5bbde344d83a2142cb9448d26d1','2026-04-20T09:35:37+08:00','2026-04-20T09:35:40+08:00','查询最近一个月的记录',unistr('大王，近一个月的记录有：\u000a\u000a- 护照在书房抽屉里\u000a- 今天给语音助手加上了 Web 端的界面。\u000a- 云猪肉添加了 web 端的界面\u000a- 你很喜欢自己的 MacBook\u000a- 今天优化了 voice-assistant，让 CLI 更清楚\u000a- 今天带壮壮去小公园骑车，骑了十圈。\u000a- 壮壮今天独立完成作业，只花了10分钟就写完了。\u000a- 今天给壮壮买了一个拓翼的解放卡车，他很喜欢\u000a- 从今天开始停用阿托伐他汀\u000a- 苹果笔记本的充电器放在书柜下面的蓝色布包里\u000a- 昨天帮壮壮剪了头发\u000a- 今天牙不疼了\u000a- 今天去把智齿拔了，居然没有什么感觉。还以为会很疼，结果他就用一个像套筒扳手一样的，在嘴里嘎吱嘎吱了几下，就薅下来了，全程没超过两分钟。终于以后吃东西应该不会再塞牙了。\u000a- 今天做了一个苹果全家桶的充电板，可以给手机、手表、耳机都放上去充电\u000a- 今天烤了鱼排吃的。\u000a- 儿子叫壮壮，头发太长了，想剪但孩子不肯。\u000a- 护照在书房白色柜子的第一个抽屉里。\u000a- 书房白色柜子抽屉内透明盒中存放有USB数据线测试板\u000a- AirPods放在桌上的蓝色盒子里\u000a- 拔键器在白色柜子的第二个抽屉里\u000a- 小狗于2026年4月11日洗澡。\u000a- 显示器支架板于2026年4月11日安装完成。\u000a- 伊朗和美国达成两周停火协议\u000a- 儿子壮壮于2026年4月11日去打篮球了。\u000a- 于2026年4月10日仅睡了四个小时，并在2026年4月11日下午小憩后有所改善。\u000a- 停药后血压升高，并于2026年4月11日恢复服用降压药。\u000a- 苗高新于2026年4月12日生病。\u000a- 你于2026年4月12日犯了错误。\u000a- 和儿子壮壮于2026年4月12日去了一个小公园，但地面有水，壮壮不愿玩。\u000a- 把谷歌登录验证码放在了书架上的《使用Python进行数据分析》这本书里。\u000a- 儿子壮壮今天去春游，被同学扔来的薯片划伤了脸。 \u000a- 医保卡在卧室多层柜的盒子里'),0.0,0.0,0,0,'cli','2026-04-20T09:35:37+08:00','soj');
