INSERT INTO session_histories VALUES(469,'2c3e545371344f769188efbc3b80833e','2026-04-20T09:44:14+08:00','2026-04-20T09:44:37+08:00','查询我的智齿的事情。',unistr('## 查询智齿拔除情况\u000a\u000a根据现有记录，你在 **4月15日** 进行了智齿拔除手术，整个过程仅用了不到两分钟，且没有明显疼痛。手术后，**4月16日** 你反馈牙齿不再疼痛。\u000a\u000a手术中使用的器械类似套筒扳手，在口内进行简单操作后，智齿被成功拔除。现在，吃东西时应该不会再出现塞牙的情况。'),1.0,0.1764276207858395118,1,0,'gui','2026-04-20T09:44:14+08:00','soj');
