INSERT INTO remember_entries_simple_fts_content VALUES(3,'用户和儿子壮壮于2026年4月12日去了一个小公园，但地面有水，壮壮不愿玩。','今天我和壮壮去小公园玩的，然后地上有水，他就不乐意去玩了。','a905b842c24f431a8cb6bb1dd1e27b35');
