INSERT INTO remember_entries_simple_fts_content VALUES(21,'今天去把智齿拔了，居然没有什么感觉。我还以为会很疼，结果他就用一个像套筒扳手一样的，在嘴里嘎吱嘎吱了几下，就薅下来了，全程没超过两分钟。终于以后吃东西应该不会再塞牙了。','记录一下: 今天去把智齿拔了，居然没有什么感觉。我还以为会很疼，结果他就用一个像套筒扳手一样的，在嘴里嘎吱嘎吱了几下，就薅下来了，全程没超过两分钟。终于以后吃东西应该不会再塞牙了','6c7013cb6659451b866503d3f76642df');
